                    nt.is_bst() &&
                    nt.view() =~= node.view().remove(res.1) &&
                    (forall |x| #[trigger] nt.view().contains(x) ==> res.1 < x)
                },
                None => node.view() =~= Set::empty().insert(res.1),
            }
