                        (Some(l), Some(r)) => {
                            let ghost r_view = r.view();
                            let (new_right, min_val) = extract_min(r);

                            // Proof: min_val is suitable to replace the current root
                            assert(r_view.contains(min_val));
                            assert(forall |x| #[trigger] r_view.contains(x) ==> x > val);
